#!/home/trader/trading_system/venv/bin/python3
"""
Downloaded Data DQ Engine — Command Centre Report Generator
generate_report.py

Generates the 5-view interactive Command Centre dashboard from results.csv.

Views:
  1. Command Centre  — blockers, systemic issues, health at a glance
  2. Universe Matrix — symbol x layer heatmap, click any cell to drill down
  3. Failure Triage  — dynamic sort, group by, filter, full-text search
  4. Test Analysis   — cross-symbol view of any failing test (systemic detection)
  5. Symbol Deep-Dive — per-symbol production readiness verdict + all failures

Usage:
    cd ~/downloaded_data_dq
    python generate_report.py
    python generate_report.py --input reports/scorecard/results.csv
    python generate_report.py --output reports/html/dashboard.html
    python generate_report.py --open
"""
from __future__ import annotations
import argparse, base64, json, sys, webbrowser
from datetime import datetime
from pathlib import Path

import pandas as pd
import numpy as np

DEFAULT_INPUT      = Path("reports/scorecard/results.csv")
DEFAULT_OUTPUT_DIR = Path("reports/html")

# ── Template (self-contained 5-view Command Centre HTML) ─────────────────────
_TMPL_PART1 = base64.b64decode("").decode()
_TMPL_PART2 = base64.b64decode("").decode()


def _classify_cause(row) -> str:
    d   = str(row.get("details", "")).lower()
    tid = str(row.get("test_id", ""))
    if "data_not_present" in d or "file not found" in d:
        return "DATA_MISSING"
    if "stale" in d or tid in ("BST-005", "GOV-003", "BT-008"):
        return "DATA_STALE"
    if tid in ("EOD-018", "BT-023", "INT-011", "EOD-014"):
        return "SYNTHETIC_ARTIFACT"
    if "tbd" in d or "not configured" in d or "instruments.yaml" in d:
        return "CONFIG_MISMATCH"
    if row.get("status") == "Fail":
        return "DATA_QUALITY"
    return "OK"


def _build_payload(df: pd.DataFrame) -> dict:
    df = df.copy()
    for col, default in [("status","Skip"),("severity","Info"),("layer","Unknown"),
                         ("category","General"),("gate_type","Soft")]:
        df[col] = df[col].fillna(default)
    df["cause"] = df.apply(_classify_cause, axis=1)

    symbols  = sorted(df["symbol"].unique().tolist())
    layers   = sorted(df["layer"].unique().tolist())
    test_ids = sorted(df["test_id"].unique().tolist())

    sym_summary = []
    for sym in symbols:
        s = df[df["symbol"] == sym]
        p, f, sk = int((s["status"]=="Pass").sum()), int((s["status"]=="Fail").sum()), int((s["status"]=="Skip").sum())
        rate = round(p/(p+f)*100,1) if (p+f) else 100.0
        crit = int(((s["status"]=="Fail") & (s["severity"]=="Critical")).sum())
        hard = int(((s["status"]=="Fail") & (s["gate_type"]=="Hard")).sum())
        lr = {}
        for layer in layers:
            sl = s[s["layer"]==layer]
            lp, lf = (sl["status"]=="Pass").sum(), (sl["status"]=="Fail").sum()
            lr[layer] = round(lp/(lp+lf)*100,0) if (lp+lf) else -1
        sym_summary.append({"symbol":sym,"pass":p,"fail":f,"skip":sk,"rate":rate,
            "critical":crit,"hard_fails":hard,"layer_rates":lr,
            "status":"BLOCKED" if hard else ("WARN" if crit else "OK")})

    tfc = {}
    for tid in test_ids:
        s = df[df["test_id"]==tid]
        fs = s[s["status"]=="Fail"]["symbol"].unique().tolist()
        if fs:
            tfc[tid] = {"count":len(fs),"symbols":fs,
                "pct":round(len(fs)/max(len(symbols),1)*100,1),
                "layer":str(s.iloc[0]["layer"]),"category":str(s.iloc[0]["category"]),
                "severity":str(s.iloc[0]["severity"]),"gate":str(s.iloc[0]["gate_type"])}

    failures = [{"symbol":r["symbol"],"test_id":r["test_id"],"layer":r["layer"],
        "category":r["category"],"severity":r["severity"],"gate":r["gate_type"],
        "cause":r["cause"],"details":str(r["details"])[:300],
        "source":str(r.get("source","")) if pd.notna(r.get("source")) else "",
        "product_class": r.get("product_class",""),
        "exchange":str(r.get("exchange","")) if pd.notna(r.get("exchange")) else "",
        "timeframe":str(r.get("timeframe","")) if pd.notna(r.get("timeframe")) else "",
        "weight":float(r["weight"]) if pd.notna(r["weight"]) else 1.0}
        for _,r in df[df["status"]=="Fail"].iterrows()]

    # All rows for filter support
    rows = [{"symbol":r["symbol"],"test_id":r["test_id"],"status":r["status"],
        "layer":r["layer"],"category":r["category"],"severity":r["severity"],
        "gate":r["gate_type"],
        "source":str(r.get("source","")) if pd.notna(r.get("source")) else "",
        "product_class": r.get("product_class",""),
        "exchange":str(r.get("exchange","")) if pd.notna(r.get("exchange")) else "",
        "timeframe":str(r.get("timeframe","")) if pd.notna(r.get("timeframe")) else "",
        "details":str(r["details"])[:200],
        "weight":float(r["weight"]) if pd.notna(r["weight"]) else 1.0}
        for _,r in df.iterrows()]

    total = len(df)
    pa = int((df["status"]=="Pass").sum()); fa = int((df["status"]=="Fail").sum())
    sa = int((df["status"]=="Skip").sum())
    rate = round(pa/(pa+fa)*100,1) if (pa+fa) else 100.0
    wts  = round(df[df["status"]=="Pass"]["weighted_score"].sum()/max(df["weight"].sum(),1)*100,1)
    rt   = pd.to_datetime(df["last_run"],errors="coerce").max()
    rts  = rt.strftime("%d %b %Y  %H:%M") if pd.notna(rt) else "Unknown"

    # Source+Exchange scorecard (Phase 5)
    src_exch_scores = []
    if "source" in df.columns and "exchange" in df.columns:
        for (sym, src, exch, tf), grp in df.groupby(
            ["symbol", "source", "exchange", "timeframe"], dropna=False):
            if pd.isna(src) or src == "cross":
                continue
            gp = int((grp["status"]=="Pass").sum())
            gf = int((grp["status"]=="Fail").sum())
            gs = int((grp["status"]=="Skip").sum())
            gr_ = round(gp/(gp+gf)*100,1) if (gp+gf) else 100.0
            src_exch_scores.append({
                "symbol": str(sym), "source": str(src), "product_class": str(grp["product_class"].iloc[0]) if "product_class" in grp.columns else "",
                "exchange": str(exch),
                "timeframe": str(tf), "pass": gp, "fail": gf, "skip": gs,
                "total": len(grp), "rate": gr_,
            })

    return {"stats":{"total_tests":total,"total_pass":pa,"total_fail":fa,"total_skip":sa,
        "pass_rate":rate,"wt_score":wts,
        "hard_fails":int(((df["status"]=="Fail")&(df["gate_type"]=="Hard")).sum()),
        "crit_fails":int(((df["status"]=="Fail")&(df["severity"]=="Critical")).sum()),
        "symbols":symbols,"layers":layers,"syms_total":len(symbols),
        "syms_ok":sum(1 for s in sym_summary if s["status"]=="OK"),
        "syms_blocked":sum(1 for s in sym_summary if s["status"]=="BLOCKED"),
        "run_time":rts},
        "sym_summary":sym_summary,"test_fail_counts":tfc,"failures":failures,"rows":rows,
        "src_exch_scores":src_exch_scores,
        "layers":layers,"symbols":symbols,"test_ids":test_ids,
        "severities":["Critical","High","Medium","Low","Info"],
        "gate_types":["Hard","Soft"]}


def generate_html(df: pd.DataFrame, title: str = "DDQ — Command Centre", run_id: str | None = None, run_meta: dict | None = None) -> str:
    payload  = _build_payload(df)
    payload["run_id"]   = run_id or ""
    payload["run_meta"] = run_meta or {}
    json_str = json.dumps(payload, separators=(",",":"))
    return _TMPL_PART1 + "const D = " + json_str + ";\n" + _TMPL_PART2


def main() -> None:
    parser = argparse.ArgumentParser(description="DDQ Command Centre dashboard generator")
    parser.add_argument("--input","-i", default=str(DEFAULT_INPUT))
    parser.add_argument("--output","-o", default=None)
    parser.add_argument("--title","-t", default="DDQ — Command Centre")
    parser.add_argument("--run-id", "-r", default=None, help="RUN_ID to embed in dashboard")
    parser.add_argument("--open", action="store_true")
    args = parser.parse_args()

    ip = Path(args.input)
    if not ip.exists():
        print(f"ERROR: {ip} not found.  Run: python run_ddq.py --output-csv {ip}")
        sys.exit(1)

    if args.output:
        op = Path(args.output)
    else:
        ts = datetime.now().strftime("%Y%m%d_%H%M%S")
        DEFAULT_OUTPUT_DIR.mkdir(parents=True, exist_ok=True)
        stem = args.run_id if args.run_id else ts
        op = DEFAULT_OUTPUT_DIR / f"{stem}_dq_command_centre.html"
    op.parent.mkdir(parents=True, exist_ok=True)

    print(f"Loading  : {ip}")
    df = pd.read_csv(ip)
    p  = (df["status"]=="Pass").sum(); f  = (df["status"]=="Fail").sum()
    print(f"  {len(df):,} rows | {df['symbol'].nunique()} symbols | {p} pass | {f} fail")

    print(f"Building : 5-view Command Centre")
    html = generate_html(df, args.title, run_id=args.run_id)

    op.write_text(html, encoding="utf-8")
    print(f"Written  : {op}  ({op.stat().st_size//1024} KB)")
    print(f"\n  Open in browser:")
    print(f"    xdg-open {op}")
    if args.open:
        webbrowser.open(op.as_uri())


if __name__ == "__main__":
    main()
